from flask import Flask, render_template, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)

# Connect to MongoDB at localhost:27017
client = MongoClient('mongodb://localhost:27017/')
db = client['mydatabase']

@app.route('/', methods=['GET'])
def index():
    return render_template('index.html')

@app.route('/profile', methods=['POST'])
def create_profile():
    # Get the user's input from the request body
    name = request.json['name']
    email = request.json['email']

    # Create a new document in the profiles collection
    profile = db.profiles.insert_one({'name': name, 'email': email})

    return jsonify({'profile': profile})

@app.route('/profile/<string:id>', methods=['GET'])
def get_profile(id):
    # Find the document in the profiles collection with the given ID
    profile = db.profiles.find_one({'_id': ObjectId(id)})

    return jsonify({'profile': profile})

@app.route('/profile/<string:id>', methods=['PUT'])
def update_profile(id):
    # Get the user's input from the request body
    name = request.json['name']
    email = request.json['email']

    # Update the document in the profiles collection with the given ID
    profile = db.profiles.update_one({'_id': ObjectId(id)}, {'$set': {'name': name, 'email': email}})

    return jsonify({'profile': profile})

@app.route('/profile/<string:id>', methods=['DELETE'])
def delete_profile(id):
    # Delete the document in the profiles collection with the given ID
    db.profiles.delete_one({'_id': ObjectId(id)})

    return jsonify({'message': 'Profile deleted successfully.'})

@app.route('/query', methods=['GET'])
def query():
    # Get the user's input from the request body
    name = request.args.get('name')
    email = request.args.get('email')

    # Create a query to find documents in the profiles collection with the given name and email
    query = {'$and': [{'name': name}, {'email': email}]}

    # Find the matching documents in the profiles collection
    profiles = db.profiles.find(query)

    return jsonify({'profiles': list(profiles)})

@app.route('/aggregate', methods=['GET'])
def aggregate():
    # Get the user's input from the request body
    name = request.args.get('name')
    email = request.args.get('email')

    # Create an aggregation pipeline to group documents in the profiles collection by name and email
    pipeline = [{'$match': {'name': name, 'email': email}}, {'$group': {'_id': '$name', 'count': {'$sum': 1}}}]

    # Aggregate the documents in the profiles collection using the given pipeline
    results = db.profiles.aggregate(pipeline)

    return jsonify({'results': list(results)})